      if (!sales || !sales.length) {
        return sendJSON(res, { error: 'sales_array_required', hint: 'Body.sales debe ser array no vacío' }, 400);
      }
      if (sales.length > 200) {
        return sendJSON(res, { error: 'too_many_sales', max: 200, got: sales.length }, 400);
      }
